import{_ as s,o as n,c as a,d as e}from"./app-13115eff.js";const p="/record-moments/img/55.png",t={},o=e(`<p>朋友们，之前我们学习到了很多 vue 底层的知识，今天我们来学习如何实现一个代码风格管控工具。</p><p>我们知道，团队作战比个人开发的情况要复杂的多，比如要规范团队内代码风格、提交信息规范等，如果有一套能实现风格统一的代码可以省去不少麻烦。那如何去做呢？这就是我们今天要学的 husky。</p><h4 id="如何使用-husky" tabindex="-1"><a class="header-anchor" href="#如何使用-husky" aria-hidden="true">#</a> 如何使用 husky？</h4><p><strong>No.1</strong></p><p>首先我们要安装它，安装方式有手动安装和自动安装两种，这里我们推荐自动安装，如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// npm</span>
npx husky<span class="token operator">-</span>init <span class="token operator">&amp;&amp;</span> npm install

<span class="token comment">// pnpm</span>
pnpm dlx husky<span class="token operator">-</span>init <span class="token operator">&amp;&amp;</span> pnpm init
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><details class="custom-container details"><summary>注意</summary><p>如果您的编译工具不支持 <code>&amp;&amp;</code> 符号，可以使用 <code>-and</code> 代替。</p></details><p>命令成功执行后，项目的根目录下就会自动生成 <code>.husky</code> 文件夹，这就是为什么项目中会有它的来历了。然后，点开 <code>.husky</code> 文件会发现自动生成了好几个文件，我们只看 <code>pre-commit</code> 文件。</p><details class="custom-container details"><summary>注意</summary><p>自动安装方式比手动安装要方便，自动安装后会直接帮我们生成或修改好相应文件，如下：</p><ol><li>生成 <code>pre-commit</code> 文件，指在 commit 之前执行的逻辑存放入口，如：修改代码风格</li><li>修改 <code>package.json</code> 文件，增加 <code>prepare: husky inistall</code> 命令，让团队 pull 下代码后保持风格统一的方式</li></ol><p>为什么说 <code>prepare: husky inistall</code> 能保持风格统一？</p><p>因为 pkg 的命令也是有生命周期的，团队成员在执行 <code>npm install</code> 或 <code>pnpm install</code> 后，会自动执行该命令，进而生成相应文件，保持统一。</p><p><code>prepare</code> 执行顺序：<code>npm install</code>、<code>npm prepare</code>、<code>npm publish</code>。</p></details><p><strong>No.2</strong></p><p>然后我们打开 <code>pre-commit</code> 文件，会发现里面自动帮我们填充了内容 <code>npm test</code>，这个就是在我们提交 <code>commit</code> 之前要执行的命令，但是如果没有配置相关内容的话会报错，然后抛出错误警告码 1。这就需要我们在 <code>pkg.scripts</code> 里配置 <code>test</code> 脚本了，当然也有其他解决方法，如下：</p><ol><li>直接删掉 <code>npm test</code></li><li>执行 <code>--no-verify</code> 跳过校验</li><li>更新为其他脚本，如：<code>npx lint-staged</code></li></ol><p>这里我们使用第三种方案，校验代码风格并强制修改。</p><details class="custom-container details"><summary>注意</summary><p><code>lint-staged</code> 是一个能读取文件缓存区的插件。</p></details><p><strong>No.3</strong></p><p>我们开始安装 <code>lint-staged</code>，安装方式如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// npm</span>
npm install <span class="token operator">-</span><span class="token constant">D</span> lint<span class="token operator">-</span>staged

<span class="token comment">// pnpm</span>
pnpm add <span class="token operator">-</span><span class="token constant">D</span> lint<span class="token operator">-</span>staged
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>安装完成后，为了不仅能读取，还能修改，我们还要安装能让代码风格保持统一的工具，有 <code>eslint、prettier</code>，这里我们选择使用 <code>eslint</code>，安装如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// npm</span>
npm init @eslint<span class="token operator">/</span>config

<span class="token comment">// pnpm</span>
pnpm create @eslint<span class="token operator">/</span>config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>执行该命令后，终端面板内会开始让我们进行一系列的选择，大家可以根据需要配置自行选择。我的如下：</p><p><img src="`+p+`" alt="图片"></p><p>然后我们再创建一个 eslint 忽略文件 <code>.eslintignore</code>，可根据需要自行定义内容：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token punctuation">.</span>eslintrc<span class="token punctuation">.</span>js
<span class="token operator">**</span><span class="token operator">/</span>node_modules
<span class="token operator">**</span><span class="token operator">/</span>dist
<span class="token operator">**</span><span class="token comment">/*.md
**/</span><span class="token operator">*</span><span class="token punctuation">.</span>json
<span class="token operator">/</span>husky
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>然后我们再创建一个 <code>lintstagedrc.js</code> 配置文件，设置读取的内容以及如何修改：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token string-property property">&quot;src/**/*.{js, ts}&quot;</span><span class="token operator">:</span> <span class="token string">&quot;eslint --fix&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><details class="custom-container details"><summary>注意</summary><p>创建/修改文件内容等，不要通过 <code>echo</code> 命令，其生成的内容为 <code>utf-16</code> 编码，会导致运行错误。</p></details><p>这个时候我们就可以更新 <code>pre-commit</code> 文件里的命令了，如下：</p><p><code>npx lint-staged</code></p><p>这样，在进行 commit 之前，就会执行我们的 <code>lint-staged</code> 命令，进而修改为统一格式，然后真正提交。</p><p><strong>No.4</strong></p><p>我们还可以对提交的描述信息进行风格统一，同样，我们执行命令如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 一步到位</span>
npx husky add <span class="token punctuation">.</span>husky<span class="token operator">/</span>commit<span class="token operator">-</span>msg <span class="token string">&#39;npx --no -- commitlint --edit \${1}&#39;</span>

<span class="token comment">// 分两步</span>
npm pkg <span class="token keyword">set</span> scripts<span class="token punctuation">.</span>commitlint<span class="token operator">=</span><span class="token string">&quot;commitlint --edit&quot;</span>
npx husky add <span class="token punctuation">.</span>husky<span class="token operator">/</span>commit<span class="token operator">-</span>msg <span class="token string">&#39;npm run commitlint \${1}&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样，<code>.husky</code> 文件夹下就会生成 <code>commit-msg</code> 文件，文件内容如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>npx <span class="token operator">--</span>no <span class="token operator">--</span> commitlint <span class="token operator">--</span>edit $<span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><details class="custom-container details"><summary>注意</summary><ol><li><code>npx --no</code> 表示只执行本地的依赖，找不到不去安装</li><li><code>\${1}</code> 表示读取的文件名，指存储最后一次提交信息的文件 <code>.git/COMMIT_EDITMSG</code></li><li><code>commitlint --edit \${1}</code> 表示从文件里读取内容进行校验</li></ol></details><p>然后，我们再安装相关依赖如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// npm</span>
npm install <span class="token operator">--</span>save<span class="token operator">-</span>dev @commitlint<span class="token operator">/</span>config<span class="token operator">-</span>conventional @commitlint<span class="token operator">/</span>cli

<span class="token comment">// pnpm</span>
pnpm add <span class="token operator">-</span><span class="token constant">D</span> @commitlint<span class="token operator">/</span>config<span class="token operator">-</span>conventional @commitlint<span class="token operator">/</span>cli
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>至这里，其实我们的 <code>commitlint</code> 就体现作用了，只不过，在提交信息时会提示我们创建一个 <code>commitlint.config.js</code> 配置文件，该文件存储的是我们对描述信息的校验规则，如下：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">entends</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;@commitlint/config-conventional&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
    <span class="token literal-property property">rules</span><span class="token operator">:</span> <span class="token punctuation">{</span>
        <span class="token string-property property">&quot;type-case&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;always&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;lowerCase&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// enum 类型为小写</span>
        <span class="token string-property property">&quot;type-empty&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;never&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 类型不能为空</span>
        <span class="token string-property property">&quot;subject-case&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;never&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 内容以空格间隔时写法，范围-英文</span>
        <span class="token string-property property">&quot;subject-empty&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;never&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 内容不允许有空格</span>
        <span class="token string-property property">&quot;subject-full-stop&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;never&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;.&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 匹配到描述内容的结尾符号报错</span>
        <span class="token string-property property">&quot;header-max-length&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;never&#39;</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token comment">// 首行文本长度不能超过多少</span>
        <span class="token string-property property">&quot;type-enum&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token string">&#39;always&#39;</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">&#39;build&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;chore&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;ci&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;docs&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;feat&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;fix&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;perf&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;refactor&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;revert&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;style&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;test&#39;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><details class="custom-container details"><summary>注意</summary><p>这里的 <code>rules</code> 是一定要配置的，各个值也一定要是有效的命令，每个命令值为数组形式，接收多个参数（至多3个），每个位置的参数表示的含义不同：</p><ol><li>第一顺位参数值为 0 | 1 | 2，分别表示：禁用规则 | 警告 | 报错</li><li>第二顺位参数值为 <code>always</code> | <code>never</code>，<code>never</code> 表示颠倒规则</li><li>第三顺位参数为值，可不传</li></ol></details><p>这样，我们就完成了我们所有的配置工作，至此，我们的代码风格和提交描述信息等就都有了明确的规范，团队效率将会有很大的提高。</p>`,41),c=[o];function i(l,r){return n(),a("div",null,c)}const u=s(t,[["render",i],["__file","index.html.vue"]]);export{u as default};
